class ModelNew(nn.Module):
    """
    Optimized version of Model using torch.compile on conv_transpose2d.
    """
    def __init__(self, in_channels: int, out_channels: int, kernel_size: tuple, stride: tuple = (1, 1), padding: tuple = (0, 0), bias: bool = False):
        super(ModelNew, self).__init__()
        self.conv_transpose2d = nn.ConvTranspose2d(in_channels, out_channels, kernel_size, stride=stride, padding=padding, bias=bias)
        # Compile the forward method
        self.compiled = False

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        if not self.compiled:
            # Compile on first forward
            self._forward_impl = torch.compile(mode="default")(self._forward_impl)
            self.compiled = True
        return self._forward_impl(x)

    def _forward_impl(self, x: torch.Tensor) -> torch.Tensor:
        return F.conv_transpose2d(
            x,
            self.conv_transpose2d.weight,
            self.conv_transpose2d.bias if self.conv_transpose2d.bias is not None else None,
            stride=self.conv_transpose2d.stride,
            padding=self.conv_transpose2d.padding,
        )
